import React from "react";
import { Cell, Pie, PieChart, ResponsiveContainer, Tooltip } from "recharts";

const COLORS = ["#2dd4bf", "#38bdf8", "#f59e0b", "#f43f5e"];

export default function RecordQualityChart({ data = {} }) {
  const chartData = [
    { name: "Success", value: data.success || 0 },
    { name: "Fail", value: data.fail || 0 },
    { name: "Skip", value: data.skip || 0 },
    { name: "Reject", value: data.reject || 0 }
  ];

  return (
    <section className="panel-shell p-5">
      <div className="mb-5">
        <h3 className="panel-title">Record Quality</h3>
        <p className="panel-subtitle mt-2">Distribution of outcome quality across roster records.</p>
      </div>
      <div className="h-72">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie data={chartData} dataKey="value" nameKey="name" innerRadius={72} outerRadius={105} paddingAngle={4}>
              {chartData.map((entry, index) => (
                <Cell key={entry.name} fill={COLORS[index % COLORS.length]} />
              ))}
            </Pie>
            <Tooltip contentStyle={{ backgroundColor: "#020617", border: "1px solid rgba(148,163,184,0.15)", borderRadius: 18 }} />
          </PieChart>
        </ResponsiveContainer>
      </div>
      <div className="mt-2 grid grid-cols-2 gap-3">
        {chartData.map((item, index) => (
          <div key={item.name} className="rounded-2xl border border-white/10 bg-white/[0.03] px-3 py-3 text-sm text-slate-300">
            <div className="flex items-center gap-2 text-slate-200">
              <span className="inline-flex h-2.5 w-2.5 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }} />
              {item.name}
            </div>
            <div className="mt-2 text-xl font-semibold text-white">{item.value}%</div>
          </div>
        ))}
      </div>
    </section>
  );
}
