import React, { useMemo } from "react";

const STAGE_ORDER = [
  "INGESTION",
  "PRE_PROCESSING",
  "MAPPING_APPROVAL",
  "ISF_GENERATION",
  "DART_GENERATION",
  "DART_REVIEW",
  "DART_UI_VALIDATION",
  "SPS_LOAD",
  "RESOLVED"
];

function stageFromRow(row) {
  return row.LATEST_STAGE_NM || row.stage || "UNKNOWN";
}

function cellTone(value, maxValue) {
  if (!value) {
    return "bg-slate-900/60 text-slate-500";
  }
  const intensity = maxValue > 0 ? value / maxValue : 0;
  if (intensity >= 0.75) {
    return "bg-rose-500/80 text-white";
  }
  if (intensity >= 0.35) {
    return "bg-amber-400/70 text-slate-950";
  }
  return "bg-emerald-400/70 text-slate-950";
}

export default function PipelineHealthChart({ stageHealth = [], failedRos = [], focusState = "ALL" }) {
  const matrix = useMemo(() => {
    const scopedFailures = failedRos.filter((row) => !focusState || focusState === "ALL" || row.CNT_STATE === focusState);
    const topOrgs = Array.from(
      scopedFailures.reduce((acc, row) => {
        const key = row.ORG_NM || "Unknown";
        acc.set(key, (acc.get(key) || 0) + 1);
        return acc;
      }, new Map())
    )
      .sort((a, b) => b[1] - a[1])
      .slice(0, 6)
      .map(([org]) => org);

    const stages = STAGE_ORDER.filter((stage) => stageHealth.some((item) => item.stage === stage));
    const stageList = stages.length ? stages : STAGE_ORDER.slice(0, 7);
    const heatmap = stageList.map((stage) => {
      const row = { stage };
      topOrgs.forEach((org) => {
        row[org] = scopedFailures.filter((item) => (item.ORG_NM || "Unknown") === org && stageFromRow(item) === stage).length;
      });
      return row;
    });

    const maxValue = heatmap.reduce((max, row) => {
      const rowMax = topOrgs.reduce((valueMax, org) => Math.max(valueMax, row[org] || 0), 0);
      return Math.max(max, rowMax);
    }, 0);

    return { topOrgs, heatmap, maxValue };
  }, [failedRos, focusState, stageHealth]);

  return (
    <section className="panel-shell p-5">
      <div className="mb-5 flex items-start justify-between gap-4">
        <div>
          <h3 className="panel-title">Pipeline Health Heatmap</h3>
          <p className="panel-subtitle mt-2">Failed roster operations across stages and top organizations for {focusState}.</p>
        </div>
        <div className="status-pill border-white/10 bg-white/[0.04] text-slate-300">Heat intensity = failure volume</div>
      </div>

      {/* Desktop Grid View */}
      <div className="hidden md:block overflow-x-auto">
        <div className="min-w-[680px]">
          <div className="grid grid-cols-[180px_repeat(6,minmax(110px,1fr))] gap-2 text-xs uppercase tracking-[0.18em] text-slate-500">
            <div className="px-3 py-2">Stage</div>
            {matrix.topOrgs.map((org) => (
              <div key={org} className="truncate px-3 py-2">{org}</div>
            ))}
          </div>
          <div className="mt-2 space-y-2">
            {matrix.heatmap.map((row) => (
              <div key={row.stage} className="grid grid-cols-[180px_repeat(6,minmax(110px,1fr))] gap-2">
                <div className="rounded-2xl border border-white/10 bg-white/[0.03] px-3 py-3 text-sm font-medium text-slate-200">
                  {row.stage}
                </div>
                {matrix.topOrgs.map((org) => (
                  <div key={`${row.stage}-${org}`} className={`rounded-2xl border border-white/5 px-3 py-3 text-center text-sm font-semibold ${cellTone(row[org], matrix.maxValue)}`}>
                    {row[org] || 0}
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Mobile Stack View */}
      <div className="md:hidden space-y-3">
        {matrix.heatmap.map((row) => {
          const activeOrgs = matrix.topOrgs.filter(org => row[org] > 0);
          if (activeOrgs.length === 0) return null;
          
          return (
            <div key={row.stage} className="rounded-2xl border border-white/10 bg-white/[0.03] p-4 text-center">
              <div className="text-sm font-semibold text-slate-300 mb-3 pb-2 border-b border-white/5">{row.stage}</div>
              <div className="grid grid-cols-2 gap-3">
                {activeOrgs.map(org => {
                   const tone = cellTone(row[org], matrix.maxValue);
                   // Extract bg color classes roughly or just use tone directly
                   return (
                     <div key={org} className={`rounded-xl px-3 py-2 ${tone} bg-opacity-20`}> 
                       <div className="text-[10px] uppercase opacity-80 mb-1 truncate">{org}</div>
                       <div className="text-lg font-bold leading-none">{row[org]}</div>
                     </div>
                   );
                })}
              </div>
            </div>
          );
        })}
        {!matrix.heatmap.some(row => matrix.topOrgs.some(org => row[org] > 0)) && (
           <div className="text-center py-8 text-slate-500 text-sm">No failures detected in top organizations.</div>
        )}
      </div>
    </section>
  );
}
